class Solution:
    def swapPairs(self, head):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        for i in range(0, len(vals) - 1, 2):
            vals[i], vals[i + 1] = vals[i + 1], vals[i]
        out = None
        for v in reversed(vals):
            out = ListNode(v, out)
        return out

